nta.declaration:
// Global Declarations
clock stableTimer;
const int N=7;
const int StableLeaderHeartbeatCount = 50;
int heartbeatTerm;
int heartbeatCounter;

// nodes sync on this channel once StableLeaderHeartbeatCount heartbeats have been sent by a single Leader
// to symbolize that the system has reached a stable state, with one leader and the rest followers
broadcast chan stable;
broadcast chan heartbeat;

// Upper and lower bounds for election timeout (ET)
const int ET_MIN = 1000;
const int ET_MAX = 1999;

// Upper and lower bounds for heartbeat timeout (HB)
const int HBT_MIN = 50;
const int HBT_MAX = 100;

// Network delay bounds
const int NET_DELAY_MIN = 20;
const int NET_DELAY_MAX = 40;

// pendingTimeout must satisfy: 2*NET_DELAY_MAX <= pendingTimeout < ET_MIN - 2*NET_DELAY_MAX
int pendingTimeout = 2 * NET_DELAY_MAX;

// Message buffers: one slot per (src, dst)
int msg[N][N];        // 1 = vote request submitted from node i to node j , 0 = empty
int delivered[N][N];  // 1 = arrived, 0 = in flight

// Network Transmission Delay timers per (src, dst)
clock netTimer[N][N];
int netDelay[N][N];

// term according to each candidate
int candidateTerms[N];
int candidateTimeouts[N];

// Votes for each candidate
int[0,N] votes[N];

int max(int a, int b) {
    return (a > b) ? a : b;
}

int min(int a, int b) {
    return (a < b) ? a : b;
}

int rand(int min, int max) {
  return fint(random(max - min) + min);
}

template.declaration:
int splitVoteCount = 0;
int lastSeenTerm = -1;

void count() {
    for (i : int[0,N-1]) {
        if (votes[i] > 1) {
            for (j : int[0,N-1]) {
                if (i!=j && votes[i] == votes[j] && candidateTerms[i] > lastSeenTerm && candidateTerms[i] == candidateTerms[j]) {
                    splitVoteCount++;
                    lastSeenTerm = candidateTerms[i];
                }
            }
        }


    }
}

// Local Declarations
clock timer;
clock pendingTimer;
int currentTerm;
int timeout = rand(ET_MIN, ET_MAX);
int voted = false;

/**
    sendVoteRequest: sends voteRequestRPCs to all other nodes by setting msg[id][i] = 1
                     for all i in {0,.., id-1, id+1, ...,N-1}
*/ 
void sendVoteRequest() {
    for (i : int[0,N-1]) {
      netTimer[id][i] = 0;
      if (i != id) {
        candidateTerms[id] = currentTerm;
        candidateTimeouts[id] = timeout;
        msg[id][i] = 1;
        delivered[id][i] = 0;
        netDelay[id][i] = rand(NET_DELAY_MIN, NET_DELAY_MAX);
       }
    }
}

/**
    cartelVote: cast vote for the candidate with the smallest election timeout.
*/
void cartelVote() {
    int minTimeout = ET_MAX + 1;
    int minIdx = 0;

    for (j : int[0,N-1]) {
      if (delivered[j][id] == 1) {
        delivered[j][id] = 0; // clear msg
        msg[j][id] = 0; // clear msg
        if (candidateTimeouts[j] < minTimeout) {
            minTimeout = candidateTimeouts[j];
            minIdx = j;
        } 
      }
    }
    votes[minIdx] = min(votes[minIdx]+1, N);
    currentTerm = candidateTerms[minIdx];
    voted = true;
    return;    
}

/**
    hasMsg: checks if any messages have arrived for this node, from the network.
*/
bool hasMsg() {
    for (j : int[0,N-1]) {
        if (delivered[j][id] == 1)
            return true;   
    }
    return false;
}

/**
    higherTerm: checks if any other candidate has a higher term than this node.
                That is a case where this node needs to step down.
*/
bool higherTerm() {
    for (i : int[0,N-1]) {
        if (delivered[i][id] == 1 && candidateTerms[i] > currentTerm)
            return true;
    }
    return false;
}

void run() {  
    for (i : int[0,N-1]) {
      for (j : int[0,N-1]) {
        if (msg[i][j] == 1 && delivered[i][j] == 0 && netTimer[i][j] >= netDelay[i][j]) {
          delivered[i][j] = 1;
        }
      }
    }    
}

bool hasDeliverable() {  
  for (i : int[0,N-1]) {
      for (j : int[0,N-1]) {
          if (msg[i][j] == 1 && delivered[i][j] == 0 && netTimer[i][j] >= netDelay[i][j])
              return true;
      }
  }
  return false;
}

nta.system:
const int C_RED    = 0;
const int C_YELLOW = 6;
const int C_GREEN  = 1;

counter := SplitVoteCounter();
net := Network();

node0 := Node(0);
node1 := Node(1);
node2 := Node(2);
node3 := Node(3);
node4 := Node(4);
node5 := Node(5);
node6 := Node(6);

//system counter, net, node0, node1, node2, node3, node4, node5, node6;
system net, node0, node1, node2, node3, node4, node5, node6; // you have to disable the coutner to run any other statistical queries

gantt {
    node0:
      node0.Follower  -> C_RED,
      node0.Candidate -> C_YELLOW,
      node0.Leader    -> C_GREEN;

    node1:
      node1.Follower  -> C_RED,
      node1.Candidate -> C_YELLOW,
      node1.Leader    -> C_GREEN;

    node2:
      node2.Follower  -> C_RED,
      node2.Candidate -> C_YELLOW,
      node2.Leader    -> C_GREEN;

    node3:
      node3.Follower  -> C_RED,
      node3.Candidate -> C_YELLOW,
      node3.Leader    -> C_GREEN;

    node4:
      node4.Follower  -> C_RED,
      node4.Candidate -> C_YELLOW,
      node4.Leader    -> C_GREEN;
}
